css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Arial', sans-serif;
    font-size: 11pt;
    color: #333;
    line-height: 1.6;
    padding: 20px;
}

.title {
    position: relative;
    text-align: center;
    margin-bottom: 30px;
}

.logo-container {
    position: absolute;
    top: 0;
    left: 0;
}

.logo {
    max-width: 120px;
    max-height: 60px;
    display: block;
}

.title h1 {
    color: #2c3e50;
    font-size: 24pt;
    margin: 10px 0;
    font-weight: bold;
}

.title p {
    font-size: 12pt;
    color: #555;
}

.separator {
    border: none;
    border-top: 3px solid #2c3e50;
    margin: 20px 0;
}

.section-header {
    color: #2c3e50;
    padding: 10px 0;
    font-size: 14pt;
    font-weight: bold;
    margin-top: 25px;
    margin-bottom: 15px;
    border-bottom: 2px solid #2c3e50;
}

.info-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 15px;
    margin-bottom: 20px;
}

.info-box {
    border: 1px solid #ddd;
    padding: 12px;
    border-radius: 5px;
    background-color: #f9f9f9;
}

.info-box label {
    display: block;
    font-weight: bold;
    color: #2c3e50;
    margin-bottom: 5px;
    font-size: 10pt;
}

.info-box .value {
    color: #555;
    font-size: 11pt;
}

.full-width {
    grid-column: 1 / -1;
}

.text-content {
    border: 1px solid #ddd;
    padding: 15px;
    background-color: #f9f9f9;
    border-radius: 5px;
    margin-bottom: 20px;
    min-height: 80px;
}

.text-content p {
    margin: 0;
    white-space: pre-wrap;
}

table.approval-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 15px;
    margin-bottom: 30px;
}

table.approval-table th {
    background-color: #34495e;
    color: white;
    padding: 10px;
    text-align: left;
    font-size: 10pt;
    border: 1px solid #2c3e50;
}

table.approval-table td {
    padding: 10px;
    border: 1px solid #ddd;
    font-size: 10pt;
}

table.approval-table tr:nth-child(even) {
    background-color: #f9f9f9;
}

.footer {
    margin-top: 50px;
    text-align: left;
    page-break-inside: avoid;
}

.footer-logo {
    max-width: 120px;
    max-height: 60px;
}

@media print {
    body {
        padding: 10px;
    }

    .section-header {
        page-break-after: avoid;
    }

    .info-grid {
        page-break-inside: avoid;
    }
}
